			BuildMapList(selectedGame);
		}
	}

	private void BuildGameList()
	{
		_games.Clear();
		GameOption.Clear();
		int num = 0;
		foreach (MiniGamePrototype item in _prototypeManager.EnumeratePrototypes<MiniGamePrototype>())
		{
			_games.Add(item);
			GameOption.AddItem(GetLocalizedOrFallback(item.Name, item.ID), (int?)num);
			num++;
		}
		if (_games.Count == 0)
		{
			((BaseButton)CreateButton).Disabled = true;
			return;
		}
		GameOption.SelectId(0);
		UpdateGameInfo(0);
	}

	private void UpdateGameInfo(int id)
	{
		if (id >= 0 && id < _games.Count)
		{
			MiniGamePrototype miniGamePrototype = _games[id];
			ModeDescription.Text = GetLocalizedOrFallback(miniGamePrototype.Description, miniGamePrototype.Description);
			ModeMap.Text = string.Empty;
			_roundsMin = 1;
			_roundsMax = ((miniGamePrototype.MaxRounds > 0) ? miniGamePrototype.MaxRounds : 100);
			_playersMin = miniGamePrototype.MinPlayers;
			_playersMax = miniGamePrototype.MaxPlayers;
			RoundsSpinBox.IsValid = (int val) => val >= _roundsMin && val <= _roundsMax;
			MaxPlayersSpinBox.IsValid = (int val) => val >= _playersMin && val <= _playersMax;
			RoundsSpinBox.Value = Math.Clamp(miniGamePrototype.DefaultRounds, _roundsMin, _roundsMax);
			MaxPlayersSpinBox.Value = Math.Clamp(miniGamePrototype.MaxPlayers, _playersMin, _playersMax);
			BuildMapList(miniGamePrototype);
		}
	}

	private void BuildMapList(MiniGamePrototype proto)
	{
		_maps.Clear();
		MapOption.Clear();
		if (proto.Maps.Count == 0)
		{
			((Control)MapRow).Visible = false;
			_selectedMapId = string.Empty;
			ModeMap.Text = string.Empty;
			((BaseButton)CreateButton).Disabled = true;
			return;
		}
		((Control)MapRow).Visible = true;
		((BaseButton)CreateButton).Disabled = false;
		int num = 0;
		foreach (MiniGameMapDefinition map in proto.Maps)
		{
			_maps.Add(map);
			MapOption.AddItem(GetLocalizedOrFallback(map.Name, map.Id), (int?)num);
			num++;
		}
		foreach (MiniGameArenaInfo customArena in _customArenas)
		{
			MiniGameMapDefinition item = new MiniGameMapDefinition("custom:" + customArena.FileName, customArena.DisplayName, string.Empty);
			_maps.Add(item);
			MapOption.AddItem(customArena.DisplayName, (int?)num);
			num++;
		}
		MapOption.SelectId(0);
		UpdateMapInfo(0);
	}

	private void UpdateMapInfo(int id)
	{
		if (id >= 0 && id < _maps.Count)
		{
			MiniGameMapDefinition miniGameMapDefinition = _maps[id];
			_selectedMapId = miniGameMapDefinition.Id;
			string localizedOrFallback = GetLocalizedOrFallback(miniGameMapDefinition.Name, miniGameMapDefinition.Name);
			ModeMap.Text = Loc.GetString("pubg-mini-create-map", new(string, object)[1] { ("map", localizedOrFallback) });
		}
	}

	private string GetLocalizedOrFallback(string locId, string fallback)
	{
		string text = default(string);
		if (!string.IsNullOrWhiteSpace(locId) && _localizationManager.TryGetString(locId, ref text) && !string.IsNullOrWhiteSpace(text))
		{
			return text;
		}
		return fallback;
	}

	private void Submit()
	{
		if (_games.Count != 0)
		{
			int selectedId = GameOption.SelectedId;
			if (selectedId >= 0 && selectedId < _games.Count)
			{
				MiniGamePrototype miniGamePrototype = _games[selectedId];
				string arg = LobbyNameEdit.Text.Trim();
				int arg2 = Math.Clamp(RoundsSpinBox.Value, _roundsMin, _roundsMax);
				int arg3 = Math.Clamp(MaxPlayersSpinBox.Value, _playersMin, _playersMax);
				bool pressed = ((BaseButton)LockCheck).Pressed;
				string arg4 = PasswordEdit.Text.Trim();
				string empty = string.Empty;
				string selectedMapId = _selectedMapId;
				this.OnCreateLobby?.Invoke(arg, miniGamePrototype.ID, empty, selectedMapId, arg2, arg3, pressed, arg4);
				((BaseWindow)this).Close();
			}
		}
	}

	private MiniGamePrototype? GetSelectedGame()
	{
		if (_games.Count == 0)
		{
			return null;
		}
		int selectedId = GameOption.SelectedId;
		if (selectedId < 0 || selectedId >= _games.Count)
		{
			return null;
		}
		return _games[selectedId];
	}

